<template>
  <div class="category-view">
    <!--常用分类-->
    <div class="common">
      <h4 class="section-title">常用分类</h4>
      <div class="detail">
        <ul class="clear">
          <li v-for="(prod,index) in commonList" :key="index" @click="toCategory(prod.id)">
            <img :src="prod.img" :alt="prod.title">
            <p class="title">{{prod.title}}</p>
          </li>
        </ul>
      </div>
    </div>
    <!--精选合集-->
    <div class="excellent">
      <h4 class="section-title">精选合集</h4>
      <div class="detail">
        <ul>
          <li v-for="(prod,index) in excellentList" :key="index" @click="toCategory(prod.id)">
            <img :src="prod.img" :alt="prod.title" class="img">
            <div class="text">
              <h3 class="title">{{prod.title}}</h3>
              <p class="tag">{{prod.tag}}</p>
            </div>
          </li>
        </ul>
      </div>
    </div>
  </div>
</template>
<script>
  import { mapState } from 'vuex'
  export default ({
      data(){
          return {

          }
      },
      methods:{
          toCategory(id){
              this.$router.push(
                  {
                      name:'categoryDetail',
                      params:{
                          categoryId:id
                      }
                  }
              )
          }
      },
      created(){
      	this.changeTitle('分类');
      	this.changeBackground('#fff');
      },
      computed:{
          ...mapState({
              commonList: state => state.category.commonList,
              excellentList: state => state.category.excellentList
          })
      }
  })
</script>
<style lang="scss" scoped>
  $dark-color:#b0b0b0;
  .category-view{
    width:10rem;
    background-color:#fff;
    padding:0 .5333rem;
    margin:0 auto;
    font-family: NotoSansHans;
    text-align: left;
    .section-title{
      color:$dark-color;
      font-size: .32rem;
      line-height:1rem;
      font-weight:normal ;
    }
    .common{
      .section-title{
        padding-top:.4rem;
      }
      .detail{
        ul{
          width:100%;
        }
        li{
          display:inline-block;
          width:33.33%;
          height:4rem;
          text-align: center;
          img{
            width:2.8rem;
            height:2.8rem;
          }
          .title{
            line-height:.8rem;
            font-weight: 300;
            color:#022222;
          }
        }
      }
    }
    .excellent{
      .detail{
        ul{
          li{
            height:1.8667rem;
            margin-bottom:.2rem;
            text-align: left;
            vertical-align: middle;
            img.img{
              display:inline-block;
              width:1.8667rem;
              height:1.8667rem;
            }
            .text{
              display:inline-block;
              padding-left:.4rem;
              height:1.8667rem;
              overflow: hidden;
              padding-top:.32rem;
              .title{
                font-size: .4533rem;
                font-weight: 500;
                color:#022222;
                line-height:.8rem;
              }
              .tag{
                font-size: .3733rem;
                font-weight: 300;
              }
            }
          }
        }
      }
    }
  }
</style>



