<template>
  <div class="cart-view">
    <div class="main">
      <div class="store-list-wrapper">
        <div class="store-list">
          <div v-for="(store,index1) in orderList" :key="index1">
            <div class="store-wrapper">
              <p class="store-name">
                <label class="cart-checkBox-label checkList-label">
                  <span class="mint-checkbox">
                    <input type="checkbox" class="mint-checkbox-input" v-model="store.isChecked">
                    <span class="mint-checkbox-core"></span>
                  </span>
                </label>
                <span class="text" @click="toStore(store.storeId)">{{store.storeName}}</span>
                <span class="edit fr">编辑</span>
                <span class="edit fr">领券</span>
              </p>
              <div class="prod-list">
                <swipeout>
                  <swipeout-item v-for="(prod,index2) in store.list" :key="index2" :disabled="isEdit||!prod.isValid">
                    <div slot="right-menu">
                      <swipeout-button @click.native="deleteProd(prod.id)" type="warn" :width="60">删除</swipeout-button>
                    </div>
                    <div slot="content">
                      <div class="prod-wrapper" :class="{'has-border':index2<store.list.length-1,'is-invalid':!prod.isValid}">
                        <div class="img-wrapper">
                          <div class="checkbox-wrapper">
                            <label class="cart-checkBox-label checkList-label">
                              <span class="mint-checkbox">
                                <input type="checkbox" class="mint-checkbox-input" v-model="prod.isChecked" :disabled="!prod.isValid">
                                <span class="mint-checkbox-core"></span>
                              </span>
                            </label>
                          </div>
                          <img :src="prod.img" @click="toProduct(prod.prodId)">
                        </div>
                        <div class="text" @click="toProduct(prod.prodId)">
                          <h3 class="prod-name">{{prod.name}}</h3>
                          <p class="style dark-color">
                            <span>M;白色</span>
                            <svg class="icon icon-select" aria-hidden="true" v-if="isEdit">
                              <use xlink:href="#icon-xiala"></use>
                            </svg>
                          </p>
                          <p class="price active-color"><strong>&yen;{{prod.price}}</strong>&nbsp;&nbsp;&nbsp;<del class="dark-color">&yen;39.9</del></p>
                        </div>
                        <span class="count" v-if="!isEdit">&times;{{prod.count}}</span>
                        <p class="edit-line" v-if="prod.isValid&&isEdit">
                          <button class="circle-btn reduce-btn" :class="{disabled:prod.count<=1}"><label>&minus;</label></button>
                          <span class="prod-count">{{prod.count}}</span>
                          <button class="circle-btn add-btn"><label>&plus;</label></button>
                        </p>
                      </div>
                    </div>
                  </swipeout-item>
                </swipeout>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
    <div class="pay-bar" v-if="orderList.length>0">
      <div class="check-all fl" @click="checkAllProd">
        <label class="cart-checkBox-label checkList-label">
            <span class="mint-checkbox">
              <input type="checkbox" class="mint-checkbox-input" v-model="state.allChecked" @click="checkAllProd">
              <span class="mint-checkbox-core"></span>
            </span>
        </label>
        <span class="text">全选</span>
      </div>
      <div class="edit-btn fl" @click="changeEdit">{{editText}}</div>
      <div class="price-info fl">
        <p>总价：<span class="active-color">&yen;{{selectPrice}}</span></p>
        <p>优惠：<span class="active-color">&yen;{{selectCheap}}</span></p>
      </div>
      <div class="pay-btn fl" :class="{disabled:!state.canPay,active:state.canPay}" v-if="!isEdit">结算</div>
      <div class="pay-btn delete-btn fl" v-else>删除</div>
    </div>
    <div class="empty" v-if="orderList.length===0">

    </div>
  </div>
</template>
<script>
  import { mapState, mapActions} from 'vuex'
  import {Swipeout, SwipeoutButton, SwipeoutItem} from './../components/swipeout/index'
  export default ({
    components:{
      Swipeout,
      SwipeoutButton,
      SwipeoutItem
    },
    data(){
      return {
      }
    },
    methods:{
      checkAllProd(){
          this.$store.dispatch('checkAllProd',event);
      },
      ...mapActions([
        'changeEdit'
      ])
    },
    created(){
//      Object.assign(this.state,{canPay:true});
      this.changeTitle('购物车');
      this.changeBackground('#f7f7f7');
    },
    computed:{
      ...mapState({
        state: state => state.cart.ready,
        selectPrice: state => state.cart.selectPrice,
        selectCheap: state => state.cart.selectCheap,
        orderList: state => state.cart.orderList,
        isEdit: state => state.cart.isEdit,
        editText: state => state.cart.editText
      })
    }
  })
</script>
<style lang="scss">
  $active-color:#e53a40;
  $dark-color:#b0b0b0;
  .dark-color{
    color:$dark-color;
  }
  .active-color{
    color:$active-color;
  }
  .cart-view{
    width:100%;
    /*font-family: "PingFang SC";*/
    .vux-swipeout-button-warn{
      background-color:$active-color;
    }
    .mint-checkbox{
      position:relative;
      top:-2px;
    }
    .mint-checkbox-core{
      border-color:$active-color;
      width:16px;
      height:16px;
    }
    .mint-checkbox-input[disabled] + .mint-checkbox-core{
      background-color:#fff;
      border-color:#b0b0b0;
    }
    .mint-checkbox-input:checked + .mint-checkbox-core{
      background-color:$active-color;
      border-color:$active-color;
    }
    .mint-checkbox-core::after{
      top:2px;
      left:5px;
      width:3px;
      height:6px;
    }
    .pay-bar{
      position:fixed;
      bottom:1.3333rem;
      left:0;
      right:0;
      z-index: 100;
      height:1.32rem;
      line-height: 1.32rem;
      border-top:1px solid #e4e4e4;
      background-color:#fff;
      font-size: .3466rem;
      color:#222;
      text-align: center;
      .check-all{
        width:25%;
        height:1.32rem;
        padding-left:.6rem;
        text-align:left;
        border-right:1px solid #e4e4e4;
        .text{
          padding-left:.14rem;
        }
      }
      .pay-btn{
        width:20%;
        height:1.32rem;
        &.delete-btn{
          background-color:$active-color;
          color:#fff;
        }
      }
      .pay-btn.disabled{
        background-color:#e4e4e4;
        color:#5a5a5a;
      }
      .pay-btn.active{
        background-color:$active-color;
        color:#fff;
      }
      .edit-btn{
        width:18%;
        height:1.32rem;
        border-right:1px solid #e4e4e4;
      }
      .price-info{
        width:37%;
        height:1.32rem;
        padding:.2rem .32rem 0 0;
        text-align:right;
        p{
          line-height:.48rem;
          &:nth-child(2){
            font-size: .2933rem;
          }
        }
      }
    }
    .main{
      text-align: left;
      margin-bottom:2.66rem;
      .store-wrapper{
        margin-bottom:.5333rem;
        background-color:#fff;
      }
      .store-name{
        line-height:1.0666rem;
        border-bottom:1px solid #e4e4e4;
        padding:0 .2rem 0 .6rem;
        font-family: "PingFang SC";
        font-weight: 500;
        color:#222;
        span.text{
          padding-left:.2rem;
        }
        .edit{
          background-color:transparent;
          border:none;
          height:100%;
          padding:0 .2rem;
          margin-right:.2rem;
          border-radius: 2px;
        }
      }
      .prod-list{
        padding-left:.6rem;
        .prod-wrapper{
          position:relative;
          height:1.8666rem;
          padding:.6rem 0 .6rem 2.8rem;
          overflow: hidden;
          background:#fff;
          box-sizing: content-box;
          font-size: .3466rem;
          &.is-invalid{
            color:#b0b0b0;
          }
          &.has-border{
            border-bottom:1px solid #e4e4e4;
          }
          .text{

          }
          .price{
            line-height: .52rem;
            strong{
              font-size:.3466rem;
            }
          }
          .style{
            line-height: .6rem;
            position:relative;
            .icon-select{
              position:absolute;
              right:1.6rem;
              top:.14rem;
              width:.32rem;
              height:.32rem;
              color:#b0b0b0;
            }
          }
          .count{
            position:absolute;
            right:.6rem;
            bottom:.6rem;
            line-height: .52rem;
          }
        }
        .img-wrapper{
          position:absolute;
          left:0;
          top:.6rem;
          height:1.8666rem;
          width:2.5866rem;
          text-align: right;
          img{
            width:1.8666rem;
            height:1.8666rem;
          }
          .checkbox-wrapper{
            position:absolute;
            left:0;
            top:0;
            line-height:1.8666rem;
            height:100%;
            width: .72rem;
            text-align: left;
          }
        }
        .prod-name{
          line-height:.52rem;
          height:1rem;
          font-size: .3466rem;
          font-weight: 500;
          display: -webkit-box;
          -webkit-box-orient: vertical;
          -webkit-line-clamp: 2;
          overflow: hidden;
        }
      }
    }
    .edit-line{
      position:absolute;
      right:.6rem;
      bottom:.4rem;
      height:16px;
      line-height: 16px;
      width:1.6rem;
      text-align: center;
      .circle-btn{
        position:absolute;
        top:0;
        width:16px;
        height:16px;
        border-radius:50%;
        background-color:$active-color;
        color:#fff;
        font-size: 14px;
        font-weight: bold;
        outline: none;
        border:none;
        overflow: hidden;
        &.disabled{
          background-color:#f5b0b3;
        }
      }
      .reduce-btn{
        left:0;

      }
      .add-btn{
        right:0;
      }
      .prod-count{
        font-size: .3466rem;
      }
      .icon{
        color:#fff;
        width:.32rem;
        height:.32rem;
      }
    }
  }
</style>



