    export default {
        props:['keyword','isWhite']
    }
</script>
<style lang="scss" scoped>
    .search{
        width: 10rem;
        padding:.26rem;
        .bg-outter{
            width:100%;
        }
        .bg-inner{
            position:relative;
            height: 0.9rem;
            line-height:.92rem;
            padding:0 .4rem;
            text-align:left;
            border-radius: 0.4533333333333333rem;
            background-color:#e4e4e4;
            .search-link{
                display:block;
                width:100%;
                height:100%;
                color:#222;
            }
            .icon-search{
                position:absolute;
                right:.4rem;
                top:.25rem;
                color:#222;
                width:.4rem;
                height:.4rem;
            }
        }
        .bg-inner.white{
            background-color: rgba(255,255,255,.8);
        }
    }
</style>


