<template>
  <div class="index-view">
    <div class="search-wrapper">
      <search-link :keyword="searchKeyWords" :isWhite="true"></search-link>
    </div>
    <div class="scroll-view">
      <!--banner-->
      <div class="banner">
        <mt-swipe :auto="6000">
          <mt-swipe-item v-for="(item,index) in bannerList" :key="index">
            <a :href="item.link">
              <img :src="item.img">
            </a>
          </mt-swipe-item>
        </mt-swipe>
      </div>
      <!--nav-->
      <div class="nav">
        <ul class="clear">
          <li v-for="(nav,index) in navList" :key="index">
            <div @click="$router.push(nav.path)">
              <h3 class="title">{{nav.title}}</h3>
              <p class="text">{{nav.text}}</p>
            </div>
          </li>
        </ul>
      </div>
      <!--swiper-->
      <div class="my-swiper">
        <swiper :options="swiperOptions" ref="mySwiper">
          <swiper-slide v-for="(slide,index) in swiperList" :key="index">
            <div class="slide-wrapper">
              <img :src="slide.img" :alt="slide.title">
              <div class="mask">
                <div class="border">
                  <h3 class="title">{{slide.title}}</h3>
                  <p class="text">{{slide.text}}</p>
                </div>
              </div>
            </div>
          </swiper-slide>
        </swiper>
      </div>
      <!--seckill-->
      <div class="seckill">
        <router-link to="/seckill">
          <h4 class="first-title">精品秒杀</h4>
          <h2 class="second-title">限时秒杀</h2>
          <div class="time">
            <span class="count hour">{{seckill.hour}}</span>
            <span class="symbol">:</span>
            <span class="count minute">{{seckill.minute}}</span>
            <span class="symbol">:</span>
            <span class="count second">{{seckill.second}}</span>
          </div>
          <p class="next">下一场 <span>{{seckill.nextTime}}</span> 开始</p>
          <img :src="seckill.img">
        </router-link>
      </div>
      <!--fenlei-->
      <div class="fenlei">
        <div class="first-title">精选分类</div>
        <div class="fenlei-swiper">
          <swiper :options="fenleiOPtion" ref="fenleiSwiper">
            <swiper-slide v-for="(slide,index) in fenleiList" :key="index">
              <div class="fenlei-swiper-wrapper">
                <h3 class="title">{{slide.title}}</h3>
                <p class="text">{{slide.text}}</p>
                <img :src="slide.img">
              </div>
            </swiper-slide>
          </swiper>
        </div>
      </div>
      <!--recommend-->
      <div class="recommend">
        <h4 class="first-title">精选推荐</h4>
        <div class="list-wrpper">
          <ul>
            <li v-for="(prod,index) in recommendList" :key="index" @click="toProduct(prod.prodId)">
              <img :src="prod.img" :alt="prod.name" class="img">
              <div class="detail">
                <h3 class="name">{{prod.name}}</h3>
                <p class="tag">{{prod.tag}}</p>
                <p class="buyCount">{{prod.buyCount}}</p>
              </div>
            </li>
          </ul>
        </div>
      </div>
    </div>
  </div>
</template>
<script>
  import {swiper, swiperSlide} from 'vue-awesome-swiper'
  import { mapState } from 'vuex'
  import './../modules/css/swiper-3.4.2.min.css'
  import searchLink from './../components/SearchLink.vue'
  export default ({
    components:{
        swiper,
        swiperSlide,
        searchLink
    },
    data(){
        return {
            navList:[
                {
                  path:'/home/user',
                  title:'新',
                  text:'新品上市'
                },
                {
                    path:'/home/index',
                    title:'热',
                    text:'热门商品'
                },
                {
                    path:'/home/index',
                    title:'惠',
                    text:'特惠折扣'
                },
                {
                    path:'/home/index',
                    title:'精',
                    text:'精心选购'
                }
            ],
            swiperOptions:{
                pagination: '.swiper-pagination',
                slidesPerView: 'auto',
                spaceBetween: 10,
            },
            fenleiOPtion:{
                pagination: '.swiper-pagination',
                slidesPerView: 'auto',
                spaceBetween: 10
            }
        }
    },
    computed: {
        ...mapState({
            bannerList : state => state.index.bannerList,
            swiperList : state => state.index.swiperList,
            seckill : state => state.index.seckill,
            fenleiList : state => state.index.fenleiList,
            recommendList : state => state.index.recommendList,
            searchKeyWords : state => state.index.searchKeyWords
        })
    },
    created(){
    	this.changeTitle('西部母婴');
    	this.changeBackground('#f7f7f7');
    },
    mounted(){

    }
  })
</script>
<style lang="scss">
  $active-color:#e53a40;
  $dark-color:#b0b0b0;
  .index-view{
    width:100%;
    .search-wrapper{
      position:fixed;
      /*top:.26rem;*/
      left:50%;
      -webkit-transform: translate3d(-50%,0,0);
      -moz-transform: translate3d(-50%,0,0);
      -ms-transform: translate3d(-50%,0,0);
      -o-transform: translate3d(-50%,0,0);
      transform: translate3d(-50%,0,0);
      z-index: 1000;
      width: 10rem;
      padding:.26rem 0;
    }
    .scroll-view{
      width:10rem;
      margin:0 auto;
      background-color:#fff;
      -webkit-transform: translate3d(0,0,0);
      -moz-transform: translate3d(0,0,0);
      -ms-transform: translate3d(0,0,0);
      -o-transform: translate3d(0,0,0);
      transform: translate3d(0,0,0);
      .banner{
        width:10rem;
        height:4.8rem;
        img{
          width:100%;
          height:100%;
        }
        .mint-swipe-indicator{
          background:#fff;
          opacity:1;
        }
        .mint-swipe-indicator.is-active{
          background:$active-color;
        }
      }
      .nav{
        width:100%;
        padding:.6rem .27rem;
        background-color:#fff;
        li{
          float:left;
          width:25%;
          >div{
            color:#5a5a5a;
            diaplay:block;
            .title{
              color:$active-color;
              font-size:.62rem;
              line-height:1.2rem;
              font-family: NotoSansHans;
              font-weight: 900;
            }
            .text{
              font-size: .24rem;
              line-height:.6rem;
            }
          }
        }
      }
      .my-swiper{
        width:100%;
        .swiper-wrapper{
          -webkit-transform: translate3d(-4.86rem,0,0);
          -moz-transform: translate3d(-4.86rem,0,0);
          -ms-transform: translate3d(-4.86rem,0,0);
          -o-transform: translate3d(-4.86rem,0,0);
          transform: translate3d(-4.86rem,0,0);
        }
        .swiper-slide{
          position:relative;
          width:6.4rem;
          height:3.73rem;
          margin-right:.26rem;
          img{
            width:100%;
            height:3.73rem;
          }
          .mask{
            position:absolute;
            left:0;
            right:0;
            top:0;
            bottom:0;
            padding:.26rem;
            background-color:rgba(30,30,30,.5);
            color:#fff;
            text-align:center;
            font-family: NotoSansHans;
            .border{
              width:100%;
              height:100%;
              padding:.8rem 0;
              border:1px solid #fff;
              .title{
                font-size: .4533rem;
                line-height:.8rem;
                font-weight: 500;
              }
              .text{
                font-size:.3733rem;
                line-height:.6rem;
                font-weight: 300;
              }
            }
          }
        }
      }
      .seckill{
        position:relative;
        width:100%;
        padding:.56rem;
        background:#fff;
        text-align:left;
        color:$dark-color;
        >a{
          color:#b0b0b0;
          display:block;
        }
        .first-title{
          font-size: .24rem;
          line-height:.8rem;
          font-weight: normal;
        }
        .second-title{
          font-size: .48rem;
          color:$active-color;
          line-height:.8rem;
        }
        .time{
          height:1.06rem;
          line-height:1.06rem;
          margin:.24rem 0;
          vertical-align: middle;
          >span{
            display:block;
            float:left;
            height:1.06rem;
            text-align:center;
          }
          .count{
            width:1.06rem;
            background-color:$active-color;
            color:#fff;
            font-size: .58rem;
          }
          .symbol{
            width:.4rem;
            font-size: .8rem;
            color:$active-color
          }
        }
        img{
          position:absolute;
          right:.5rem;
          top:1rem;
          width:2.6rem;
          height:2.6rem;
        }
      }
      .fenlei{
        width:100%;
        padding-left:.56rem;
        background-color:#fff;
        text-align:center;
        font-family: NotoSansHans;
        margin-bottom:.2rem;
        .first-title{
          text-align:left;
          color:$dark-color;
          font-weight: normal;
          font-size: .24rem;
          line-height:.8rem;
        }
        .swiper-slide{
          position:relative;
          width:3.47rem;
          height:3.47rem;
          padding-top:.2rem;
          background-color:#f6f6f6;
          color:#022222;
          overflow: hidden;
          .title{
            font-size:.453rem;
            font-weight:500;
            line-height:.8rem;
          }
          .text{
            font-size: .373rem;
            font-weight:300;
            line-height:.6rem;
          }
          img{
            position:absolute;
            bottom:0;
            left:50%;
            -webkit-transform: translate3d(-50%,0,0);
            -moz-transform: translate3d(-50%,0,0);
            -ms-transform: translate3d(-50%,0,0);
            -o-transform: translate3d(-50%,0,0);
            transform: translate3d(-50%,0,0);
            width:1.76rem;
            height:1.493rem;
          }
        }
      }
      .recommend{
        width:100%;
        background-color:#fff;
        padding-left:.56rem;
        font-family: NotoSansHans;
        .first-title{
          text-align:left;
          color:$dark-color;
          font-weight: normal;
          font-size: .24rem;
          line-height:.8rem;
        }
        li{
          height:1.86rem;
          text-align: left;
          margin-bottom:.4rem;
          color:#022222;
          img{
            display:inline-block;
            width:1.86rem;
            height:1.86rem;
          }
          .detail{
            display:inline-block;
            height:1.86rem;
            padding-left:.2rem;
            overflow: hidden;

          }
          .name{
            font-size: .4533rem;
            font-weight: 500;
            /*color:#022222;*/
            line-height:.8rem;
          }
          .tag{
            font-size: .3733rem;
            font-weight:300 ;
            line-height:.6rem;
          }
          .buyCount{
            font-size: .32rem;
            font-weight: 300;
          }
        }
