import Vue from 'vue'
import Router from 'vue-router'
import Home from './../views/Home.vue'
import Index from './../views/Index.vue'
import Category from './../views/Category.vue'
import CategoryDetail from './../views/CategoryDetail.vue'
import Cart from './../views/Cart.vue'
import User from './../views/User.vue'
import Order from '../views/Order.vue'
import Search from './../views/Search.vue'
import Points from '../views/Points.vue'
import Seckill from './../views/Seckill.vue'
import StoreCollect from './../views/StoreCollect.vue'
import Track from './../views/Track.vue'
import Product from './../views/Product.vue'
import OrderDetail from './../views/OrderDetail.vue'
import RateOrder from './../views/RateOrder.vue'
import Store from './../views/Store.vue'
import SearchList from './../views/SearchList.vue'
import Login from './../views/Login.vue'

Vue.use(Router)

const router=new Router({
  routes: [
    {
      path: '/home',
      name: 'home',
      component: Home,
      children:[
        {
          path: '/home/index',
          name: 'Index',
          component: Index
        },
        {
          path: '/home/category',
          name: 'Category',
          component: Category
        },
        {
          path: '/home/cart',
          name: 'Cart',
          component: Cart
        },
        {
          path: '/home/user',
          name: 'User',
          component: User
        },
      ]
    },
    {
      path:'/categoryDetail/:categoryId',
      name:'categoryDetail',
      component:CategoryDetail
    },
    {
      path:'/order/:type',
      name:'order',
      component:Order
    },
    {
      path:'/search',
      name:'search',
      component:Search
    },
    {
      path:'/points',
      name:'points',
      component:Points
    },
    {
      path:'/seckill',
      name:'seckill',
      component:Seckill
    },
    {
      path:'/storeCollect',
      name:'storeCollect',
      component:StoreCollect
    },
    {
      path:'/track',
      name:'track',
      component:Track
    },
    {
      path:'/product/:prodId',
      name:'product',
      component:Product
    },
    {
      path:'/orderDetail/:orderId',
      name:'orderDetail',
      component:OrderDetail
    },
		{
			path:'/rateOrder/:orderId/:prodId',
			name:'rateOrder',
			component:RateOrder
		},
    {
      path:'/store/:storeId',
      name:'store',
      component:Store
    },
    {
      path:'/searchList/:keyword',
      name:'searchList',
      component:SearchList
    },
    {
      path:'/login',
      name:'login',
      component:Login
    }
    // {
    //   path:'*',
    //   component:NotFound,
    //   name:'404'
    // }
  ]
});
router.afterEach(function (to) {
  if (window.ga) {
    window.ga('set', 'page', to.fullPath); // 你可能想根据请求参数添加其他参数，可以修改这里的 to.fullPath
    window.ga('send', 'pageview');
  }
});
export {router}



