// The Vue build version to load with the `import` command
// (runtime-only or standalone) has been set in webpack.base.conf with an alias.
import Vue from 'vue'
import App from './App'
import {router} from './router/index'
import './modules/css/reset.css'
import 'mint-ui/lib/style.css'
// vuex
import store from './store/index'

// 引入可伸缩布局flexible
import flexible from './modules/js/flebible'
Vue.use(flexible)

// 引入iconfont
import iconfont from './modules/js/iconfont'
Vue.use(iconfont)

import vueScrollBehavior from 'vue-scroll-behavior'
Vue.use(vueScrollBehavior, { router: router })

// 引入全局方法
import util from './modules/js/util'
Vue.use(util)
// 引入Tabber,Swipe,Navbar,Button,CellSwipe
import { Tabbar, TabItem, Swipe, SwipeItem, Navbar, Button, CellSwipe, Popup} from 'mint-ui'
Vue.component(Tabbar.name, Tabbar)
Vue.component(TabItem.name, TabItem)
Vue.component(Swipe.name, Swipe)
Vue.component(SwipeItem.name, SwipeItem)
Vue.component(Navbar.name, Navbar)
Vue.component(Button.name, Button)
Vue.component(CellSwipe.name,CellSwipe)
Vue.component(Popup.name,Popup)

Vue.config.productionTip = false

/* eslint-disable no-new */
// 路由钩子
router.beforeEach((to,from,next)=>{
  if (to.path == '/') {
    next({path:'/home/index'});
  }else{
    next();
  }
});
/* eslint-disable no-new */
new Vue({
  el: '#app',
  router,
  store,
  template: '<App/>',
  components: { App }
})



