<template>
  <div class="user-view">
    <div class="info">
      <div class="img-wrapper" :userInfo="userInfo">
        <img :src="userInfo.photo" :alt="userInfo.name">
      </div>
      <p class="name">{{userInfo.name}}</p>
      <span class="icon-wrapper">
        <svg class="icon icon-set" aria-hidden="true">
        <use xlink:href="#icon-shezhi"></use>
      </svg>
      </span>
    </div>
    <div class="btn">
      <ul class="btn-list">
        <li>
          <button @click="$router.push('/points')">
            <p class="count">{{userInfo.points}}</p>
            <p class="name">购物积分</p>
          </button>
        </li>
        <li>
          <button @click="$router.push('/storeCollect')">
            <p class="count">{{userInfo.storeCollect}}</p>
            <p class="name">店铺关注</p>
          </button>
        </li>
        <li>
          <button @click="$router.push('/track')">
            <p class="count">{{userInfo.trackCount}}</p>
            <p class="name">浏览足迹</p>
          </button>
        </li>
      </ul>
      <span class="line line-left"></span>
      <span class="line line-right"></span>
    </div>
    <div class="my-order">
      <my-cell :options="cellOrder"></my-cell>
      <div class="list-wrapper">
        <ul class="order-list clear">
          <li v-for="type in orderTypeList" @click="$router.push(type.path)">
            <span class="icon-wrapper">
              <svg class="icon" aria-hidden="true">
                <use :xlink:href="type.icon"></use>
              </svg>
            </span>
            <p class="name">{{type.name}}</p>
          </li>
        </ul>
      </div>
    </div>
    <div class="service">
      <my-cell :options="feedBackOptions"></my-cell>
      <my-cell :options="helpOptions"></my-cell>
      <my-cell :options="phoneOptions"></my-cell>
    </div>
  </div>
</template>
<script>
  import { mapState } from 'vuex'
  import MyCell from './../components/MyCell.vue'
  export default ({
      components:{
          MyCell
      },
      data(){
          return {
//              我的订单
              cellOrder:{
                  title:'我的订单',
                  text:'查看全部',
                  path:'#/order/all'
              },
//              反馈
              feedBackOptions:{
                  title:'反馈',
                  text:'',
                  path:'#/feedBack'
              },
//              帮助与客服
              helpOptions:{
                  title:'帮助与客服',
                  text:'',
                  path:'#/helper'
              },
//              服务电话
              phoneOptions:{
                  title:'服务电话',
                  text:'',
                  path:'tel:10010'
              },
              orderTypeList:[
                  {
                      icon:'#icon-fukuan',
                      name:'待付款',
                      path:{
                          name:'order',
                          params:{
                              type:'waitPay'
                          }
                      },
                  },
                  {
                      icon:'#icon-fahuo',
                      name:'待发货',
                      path:{
                          name:'order',
                          params:{
                              type:'waitSend'
                          }
                      },
                  },
                  {
                      icon:'#icon-shouhuo',
                      name:'待收货',
                      path:{
                          name:'order',
                          params:{
                              type:'waitReceive'
                          }
                      },
                  },
                  {
                      icon:'#icon-pingjia',
                      name:'待评价',
                      path:{
                          name:'order',
                          params:{
                              type:'waitRate'
                          }
                      },
                  },
                  {
                      icon:'#icon-tuikuan',
                      name:'待退款',
                      path:{
                          name:'order',
                          params:{
                              type:'waitReturn'
                          }
                      },
                  }
              ]
          }
      },
      created(){
      	this.changeTitle('用户中心');
      	this.changeBackground('#f7f7f7');
      },
      computed:{
          ...mapState({
              userInfo : state => state.user.userInfo
          })
      }
  })
</script>
<style lang="scss">
  $main-color:#222;
  $dark-color:#5a5a5a;
  .user-view{
    width:10rem;
    margin:0 auto;
    /*font-family: NotoSansHans;*/
    .info{
      position:relative;
      width:100%;
      height:3.4933rem;
      background-color:#d43b40;
      color:#fff;
      .img-wrapper{
        padding-top:.5866rem;
        img{
          width:1.6rem;
          height:1.6rem;
          border-radius: 50%;
          border:2px solid rgba(255,255,255,.4);
        }
      }
      .name{
        font-size: .3733rem;
        font-weight: 300;
        line-height:.8rem;
      }
      .icon-wrapper{
        position:absolute;
        right:.5866rem;
        top:.5866rem;
      }
      .icon-set{
        color:#fff;
        width:.58rem;
        height:.58rem;
      }
    }
    .btn{
      margin-bottom:.4rem;
      background-color:#fff;
      .btn-list{
        width:100%;
        &:after{
          clear:both;
          display:block;
          content:'';
        }
        li{
          width:33.33%;
          height:1.3333rem;
          float:left;
          overflow: hidden;
          button{
            width:100%;
            height:100%;
            -webkit-appearance: none;
            background-color:#fff;
            border:none;
            .count{
              font-size: .4rem;
              font-weight: 500;
              color:$main-color;
              line-height:.6rem;
            }
            .name{
              font-size: .2666rem;
              color:$dark-color;
            }
          }
        }
      }
    }
    .my-order{
      text-align: left;
      margin-bottom:.4rem;
      .list-wrapper{
        padding:.4rem .2rem;
        background-color:#fff;
      }
      .order-list{
        text-align: center;
        background-color:#fff;
        li{
          float:left;
          width:20%;
          color:#5a5a5a;
          .icon{
            color:#5a5a5a;
          }
          .name{
            line-height:.6rem;
          }
        }
      }
    }
  }
</style>



