            color:#5a5a5a;
            line-height: .54rem;
            margin-bottom:.2rem;
          }
        }
      }
      .other-info-section{
        font-size: .3466rem;
        line-height:.54rem;
        padding-left:.6rem;
        color:#5a5a5a;
        background-color:#fff;
        margin-bottom:.32rem;
        .cell{
          position:relative;
          padding:.36rem 0 .36rem 1rem;
          label{
            position:absolute;
            top:.36rem;
            left:0;
          }
        }
        .cell-sales .content{
          color:#f86368;
        }
      }
      .rate-section{
        position: relative;
        margin-bottom:.32rem;
        color:#5a5a5a;
        background-color:#fff;
        padding:.32rem 0 .32rem .6rem;
        overflow: hidden;
        .wrapper{
          width:120%;
        }
        .title{
          line-height:.6rem;
          margin-bottom:.4rem;
          font-size: .3466rem;
        }
        .total-count{
          color:#f86368;
        }
        .rate-child{
          position:relative;
          width:6.12rem;
          height:3.4666rem;
          padding:.32rem 2.92rem .32rem .32rem;
          border:1px solid #e4e4e4;
          line-height:.48rem;
          .img-wrapper{
            position:absolute;
            right:.32rem;
            top:.32rem;
          }
          img{
            width:2.4rem;
            height:2.8266rem;
          }
          .name{
            color:#b0b0b0;
            margin-bottom:.2rem;
          }
        }
        .see-all{
          height:3.4666rem;
          width:3.4666rem;
          padding:1.2rem 0;
          text-align: center;
          border:1px solid #e4e4e4;
          margin-left:.32rem;
          p{
            line-height:.48rem;
          }
        }
      }
      .recommend-section{
        background-color:#fff;
        padding:.32rem 0 .32rem .6rem;
        color:#5a5a5a;
        margin-bottom:.32rem;
        .top{
          padding-right:.6rem;
          margin-bottom:.2rem;
          line-height:.6rem;
          .total{
            font-size: .3466rem;
          }
          .save{
            text-align: right;
            color:#b0b0b0;
          }
        }
        .content{
          margin-top:.2rem;
          .title{
            line-height:.4rem;
            height:.8rem;
            display: -webkit-box;
            -webkit-box-orient: vertical;
            -webkit-line-clamp: 2;
            overflow: hidden;
          }
          .price{
            line-height:.6rem;
          }
        }
      }
      .price-wrapper{
        padding-left:.6rem;
        .wrapper{
          height:1.32rem;
          line-height:1.32rem;
          border-bottom:1px solid #e4e4e4;
        }
        .symbol{
          font-size:.4rem;
        }
        .current-price{
          font-size: .6666rem;
          padding-left:2px;
        }
        .original-price{
          color:#b0b0b0;
          padding-left:4px;
        }
        .tag{
          position:relative;
          top:-3px;
          left:4px;
          display:inline-block;
          width:1.0666rem;
          height:.48rem;
          line-height: .48rem;
          text-align: center;
          background-color:#f86368;
          color:#fff;
          border-radius: 3px;
        }
      }
      .swiper-slide{
        width:3.2rem;
        img{
          width:3.2rem;
          height:3.2rem;
        }
      }

      /*详情*/
      .detail-section{
        background-color:#fff;
        padding:.2rem 0;
        color:#5a5a5a;
        .hint{
          line-height:1rem;
          text-align: center;
          font-size: .3466rem;
          padding-bottom:1rem;
        }
      }
    }
    .mint-popup{
      .popup{
        border-top:1px solid #e4e4e4;
      }
      width:100%;
      background-color:rgba(255,255,255,.95);
      font-size: .3733rem;
      .popup-btn{
        width:100%;
        height:1.16rem;
        font-size: .4266rem;
      }
      .popup-btn-white{
        border:1px solid $active-color;
        border-radius: 5px;
        background-color:rgba(255,255,255,.95);
        color:$active-color;
      }
      .popup-btn-active{
        background-color:$active-color;
        color:#fff;
        border:none;
        border-radius: 5px;
      }
      .cell{
        position:relative;
        line-height:1.4rem;
        height:1.4rem;
        padding:0 .6rem;
        border-bottom:1px solid #e4e4e4;
      }
      .cell-value{
        position:absolute;
        right:.6rem;
        top:0;
        height:100%;
        padding-right:.6rem;
        .icon-select{
          position:absolute;
          right:0;
          top:.52rem;
          color:#222;
        }
        &.no-right{
          padding-right:0;
        }
      }
      .cancel-btn{
        position:absolute;
        right:.2rem;
        top:50%;
        -webkit-transform: translate3d(0,-50%,0);
        -moz-transform: translate3d(0,-50%,0);
        -ms-transform: translate3d(0,-50%,0);
        -o-transform: translate3d(0,-50%,0);
        transform: translate3d(0,-50%,0);
        background-color:transparent;
        border:none;
        color:#5a5a5a;
        padding:.2rem .4rem;
        border-radius: 5px;
      }
      .icon-select{
        width:.36rem;
        height:.36rem;
      }
      .circle{
        position:absolute;
        top:50%;
        -webkit-transform: translate(0,-50%);
        -moz-transform: translate(0,-50%);
        -ms-transform: translate(0,-50%);
        -o-transform: translate(0,-50%);
        transform: translate(0,-50%);
        width:24px;
        height:24px;
        box-sizing: border-box;
        border-radius:50% ;
        display:inline-block;
        overflow: hidden;
      }
      .circle-select{
        right:.6rem;
      }
      .circle-add{
        left:0;
        border:1px solid #000;
        color:#000;
        line-height:24px;
        text-align: center;
        font-size: 20px;
      }
      .circle-select-core{
        position:relative;
        display:inline-block;
        width:100%;
        height:100%;
        background-color:#000;
        &::after{
          border: 1px solid #fff;
          border-left: 0;
          border-top: 0;
          content: "";
          top: 6px;
          left: 10px;
          position: absolute;
          width: 4px;
          height: 9px;
          -webkit-transform: rotate(45deg) scale(1);
          transform: rotate(45deg) scale(1);
          -webkit-transition: -webkit-transform .2s;
          transition: -webkit-transform .2s;
        }
      }
      .btn-wrapper{
        padding:.32rem .6rem;
      }
    }
    /*样式选择弹出框*/
    .style-select-popup{
      .btn-wrapper{
        height:1.66rem;
        padding:.25rem .6rem;
      }
    }
    /*样式弹出框*/
    .style-popup{
      border-top:1px solid #e4e4e4;
      .list-wrapper{
        padding:.2rem .6rem;
        min-height:4rem;
        li{
          float:left;
          padding:.32em 1.4em;
          margin:0 .6em .5em 0;
          border:1px solid #b0b0b0;
          border-radius: 3px;
          color:#b0b0b0;
          font-size: .4266rem;
          &.is-selected{
            background-color:#f86368;
            color:#fff;
            border-color:#f86368;
          }
        }
      }
      .title{
        line-height:.8rem;
      }
    }
    /*确认订单弹出框*/
    .confirm-popup{
      .icon-return{
        position:absolute;
        top:.52rem;
        left:.6rem;
      }
    }
    /*地址选择弹出框*/
    .address-select-popup{
      .address-wrapper{
        position:relative;
        padding:.4rem .6rem;
        border-bottom:1px solid #e4e4e4;
        .name{
          line-height:.6rem;
        }
        .address{
          line-height: .6rem;
          font-size: .2933rem;
        }
      }
      .address-list-wrapper{
        height:4.2rem;
        overflow: hidden;
        overflow-y: scroll;
      }
    }
    /*添加地址弹出框*/
    .address-add-popup{
      .input-list-wrapper{
        padding:0 .6rem .48rem .6rem;
      }
      .input-wrapper{
        padding-top:.32rem;
        .bg{
          height:1.06rem;
          padding:.23rem .32rem;
          background-color:#e4e4e4;
          border-radius: 2px;
        }
        input{
          width:100%;
          height:100%;
          outline: none;
          background-color:transparent;
          line-height:.64rem;
          font-size: .3733rem;
        }
        ::-webkit-input-placeholder { /* WebKit browsers */
          color:    #222;
        }
        :-moz-placeholder { /* Mozilla Firefox 4 to 18 */
          color:    #222;
        }
        ::-moz-placeholder { /* Mozilla Firefox 19+ */
          color:    #222;
        }
        :-ms-input-placeholder { /* Internet Explorer 10+ */
          color:    #222;
        }
      }
    }
    /*优惠券选择弹出框*/
    .coupon-select-popup{
      .coupon-list-wrapper{
        padding:0 .6rem;
        height:5.2rem;
        overflow:hidden;
        overflow-y:scroll;
      }
      .coupon-wrapper{
        padding-top:.32rem;
        font-size: .32rem;
      }
      .border{
        position:relative;
        height:2.08rem;
        border:1px solid #e4e4e4;
        padding:2px 0 2px 2.8rem;
        border-radius:5px;
        .money{
          position:absolute;
          left:0;
          top:0;
          width:2.8rem;
          height:100%;
          padding:.48rem 0;
          text-align: center;
          .count{
            line-height: .6rem;
          }
          .symbol{
            font-size: .3733rem;
          }
        }
        .large-font{
          font-size: .6666rem;
        }
        .content{
          height:100%;
          border-left:1px dashed #e4e4e4;
          padding:.48rem 0 .48rem .8rem;
          line-height: .48rem;
        }
      }
    }
    /*支付方式弹出框*/
    .pay-popup{
      .pay-list-wrapper{
        min-height: 5.6rem;
      }
      .pay-wrapper{
        position:relative;
        padding:.6rem .6rem .6rem 1.8rem;
        border-bottom:1px solid #e4e4e4;
        line-height:.92rem;
        .icon{
          position:absolute;
          left:.6rem;
          top:.6rem;
          width:.92rem;
          height:.92rem;
          color:#48ca2f;
        }
      }
    }
  }
  .modal-input-border{
    position:absolute;
    right:.6rem;
    top:.3rem;
    height:.8rem;
    width:3rem;
    border:1px solid #b0b0b0;
    border-radius: 3px;
    text-align: center;
    overflow: hidden;
    box-sizing: border-box;
  }
  .modal-input-border .modal-btn{
    position:absolute;
    top:0;
    display:inline-block;
    height: .8rem;
    width:.8rem;
    border:none;
    background-color:transparent;
    font-size: .8rem;
  }
  .modal-input-border .modal-input{
    position:absolute;
    top:0;
    left:50%;
    outline: none;
    z-index: 100;
    -webkit-transform: translate3d(-50%,0,0);
    -moz-transform: translate3d(-50%,0,0);
    -ms-transform: translate3d(-50%,0,0);
    -o-transform: translate3d(-50%,0,0);
    transform: translate3d(-50%,0,0);
    display:inline-block;
    width:1.4rem;
    height:100%;
    padding:2px 0;
    text-align: center;
    font-size: .4rem;
    border:1px solid #b0b0b0;
    box-sizing: border-box;
    border-top:none;
    border-bottom:none;
    background-color: transparent;
  }
  .mint-popup .modal-input-border .icon{
    position:absolute;
    top:49%;
    left:50%;
    -webkit-transform: translate3d(-50%,-49%,0);
    -moz-transform: translate3d(-50%,-49%,0);
    -ms-transform: translate3d(-50%,-49%,0);
    -o-transform: translate3d(-50%,-49%,0);
    transform: translate3d(-50%,-49%,0);
    width:.6rem;
    height:.6rem;
    color:#444;
  }
  .modal-input-border .icon.unable{
    color:#bbb;
  }
  .modal-btn-reduce{
    left:0;
  }
  .modal-btn-add{
    right:0;
  }
</style>



