// 首页模块
const state = {
	storeList:[
		{
			storeId:110,
			name:'kabrita佳贝艾特',
			prodCount:7,
			img:require('./../../assets/02/image-10.jpg'),
			isCollect:true
		},
		{
			storeId:111,
			name:'kabrita佳贝艾特',
			prodCount:7,
			img:require('./../../assets/02/image-10.jpg'),
			isCollect:true
		},
		{
			storeId:112,
			name:'kabrita佳贝艾特',
			prodCount:7,
			img:require('./../../assets/02/image-12.jpg'),
			isCollect:true
		},
		{
			storeId:113,
			name:'kabrita佳贝艾特',
			prodCount:7,
			img:require('./../../assets/02/image-12.jpg'),
			isCollect:true
		},
		{
			storeId:114,
			name:'kabrita佳贝艾特',
			prodCount:7,
			img:require('./../../assets/02/image-12.jpg'),
			isCollect:true
		}
	]
}
const mutations={
	CancelCollect(state,storeId){
		for(let [index,store] of state.storeList.entries()){
			if(store.storeId===storeId){
				store.isCollect=!store.isCollect;
			}
		}
	}
}
const actions={
	cancelCollect({commit},storeId){
		commit('CancelCollect',storeId);
	}
}
export default {
	state,
	mutations,
	actions
}


