<template>
    <div class="my-cell">
        <a :href="options.path">
            <span class="title">{{options.title}}</span>
            <span class="text">{{options.text}}</span>
            <svg class="icon icon-right" aria-hidden="true">
                <use xlink:href="#icon-right"></use>
            </svg>
        </a>
    </div>
</template>
<script>
    export default ({
        props:['options'],
        methods:{
            toPath(path){
                if(path){
                    this.$router.push(path);
                }else{
                    return false;
                }
            }
        },
    })
</script>
<style lang="scss" scoped>
    .my-cell{
        position:relative;
        width:100%;
        height:1.3333rem;
        line-height:1.36rem;
        padding:0 .92rem 0 .4rem;
        background-color:#fff;
        border-bottom:1px solid #eee;
        text-align: left;
        font-size: .4266rem;
        font-family: NotoSansHans;
        font-weight:300;
        >a{
            display:block;
        }
        .title{
            color:#222;
        }
        .text{
            float:right;
            font-size:.3466rem ;
            color:#b0b0b0;
        }
        .icon-right{
            position:absolute;
            right:.28rem;
            top:.45rem;
            width:.42rem;
            height:.42rem;
            color:#b0b0b0;
        }
        &:active{
            background-color:rgba(240,240,240,.9);
            border-color:rgba(240,240,240,.9);
        }
    }
</style>


