<template>
    <div class="storeCollect-view">
        <div class="list-wrapper">
            <ul class="store-list">
                <li v-for="(store,index) in storeList" :key="index" @click="toStore(store.storeId)">
                    <div class="wrapper">
                        <div class="img-wrapper">
                            <img :src="store.img" :alt="store.name">
                        </div>
                        <div class="text-wrapper">
                            <h3 class="name">{{store.name}}</h3>
                            <p class="count"><span class="active-color">{{store.prodCount}}个 </span>商品在销售</p>
                        </div>
                        <div class="btn-wrapper">
                            <mt-button size="small" :type="store.isCollect?'primary':'danger'" @click.native.stop="handelClick(store.storeId)">{{store.isCollect?'已关注':'关注'}}</mt-button>
                        </div>
                    </div>
                </li>
            </ul>
        </div>
    </div>
</template>
<script>
    import { mapState } from 'vuex'
    export default {
        data(){
        	return {
                buttonType:'primary'
            }
        },
        methods:{
            handelClick(storeId){
                this.$store.dispatch('cancelCollect',storeId);
            }
        },
        created(){
        	this.changeTitle('关注');
        	this.changeBackground('#fff');
        },
        computed:{
          ...mapState({
            storeList: state => state.storeCollect.storeList
          })
        }
    }
</script>
<style lang="scss">
    .storeCollect-view{
        $active-color:#e53a40;
        .active-color{
            color:$active-color;
        }
        width:100%;
        background-color:#fff;
        font-family:NotoSansHans ;
        text-align: left;
        .list-wrapper{
            padding:.2rem .52rem;
            .store-list{
                li{
                    padding:.2rem 0;
                    margin:.2rem 0;
                    .wrapper{
                        position:relative;
                        width:100%;
                        padding-left:1.72rem;
                        height:100%;
                    }
                    .img-wrapper{
                        position:absolute;
                        left:0;
                        top:0;
                        width:1.32rem;
                        height:1.32rem;
                        img{
                            width:100%;
                            height:100%;
                        }
                    }
                    .text-wrapper{
                        height:1.32rem;
                        padding-right:2rem;
                        .name{
                           font-size: .3733rem;
                            line-height:.8rem;
                            color:#222;
                            font-weight: 500;
                        }
                        .count{
                            font-size: .32rem;
                            color:#b0b0b0;
                            font-weight: 300;
                        }
                    }
                    .btn-wrapper{
                        position: absolute;
                        right:0;
                        top:.4rem;
                        z-index: 200;
                        .mint-button{
                            color:#fff;
                            font-size: .32rem;
                            height:.6133rem;
                            width:1.6rem;
                            line-height:.6133rem;
                            padding:0;
                            border:none;
                        }
                    }
                }
            }
        }
    }
</style>


