export default {
	install(Vue,options){
		Vue.prototype.changeTitle=function(title){
			document.querySelector('title').innerHTML=title;
		}
		Vue.prototype.changeBackground=function(color){
			document.body.style.backgroundColor=color;
		}
		Vue.prototype.toOrder=function(id){
			this.$router.push({
				name:'orderDetail',
				params:{
					orderId:id
				}
			})
		}
		Vue.prototype.toProduct=function(id){
			this.$router.push({
				name:'product',
				params:{
					prodId:id
				}
			})
		}
		Vue.prototype.toStore=function (id) {
			this.$router.push({
				name:'store',
				params:{
					storeId:id
				}
			})
		}
		Vue.prototype.toSearchList=function(keyword){
			this.$router.push({
				name:'searchList',
				params:{
					keyword:keyword
				}
			})
		}
	}
}


