<template>
    <div class="search-view">
        <div class="top-bar">
            <div class="bg">
                <input type="text" v-model="keyword" class="search-input" placeholder="推荐搜索关键字" @keyup="changeKeyword">
                <button class="clear-btn" @click="clearKeyword">
                    <span class="clear" v-show="keyword!==''">&times;</span>
                </button>
                <span class="icon-wrapper" @click="toSearchList(keyword)">
                    <svg class="icon icon-search" aria-hidden="true">
                        <use xlink:href="#icon-sousuo"></use>
                    </svg>
                </span>
            </div>
        </div>
        <div class="keywords">
            <div class="history">
                <p class="type">历史搜索</p>
                <ul class="list">
                    <li v-for="(word,index) in historyList" :key="index" @click="toSearchList(word)">{{word}}</li>
                </ul>
            </div>
            <div class="hot">
                <p class="type">热门搜索</p>
                <ul class="list">
                    <li v-for="(word,index) in historyList" :key="index" @click="toSearchList(word)">{{word}}</li>
                </ul>
            </div>
        </div>
    </div>
</template>
<script>
    import { mapState, mapActions, mapMutations, mapGetters} from 'vuex'
    export default ({
        data(){
            return {
                canPushState:true,
                keyword:this.getKeyword
            }
        },
        methods:{
            pushHistory(){
              let state={
                title:'搜索',
                url:'#/search'
              }
              if(this.canPushState){
                window.history.pushState(state,'首页','#/home/index');
              }
            },
            clearKeyword(){
            	this.keyword='';
            	this.$store.dispatch('clearKeyword');
            },
            changeKeyword(){

            }
        },
        computed:{
            ...mapState({
                historyList: state => state.search.historyList,
                hotList: state => state.search.hotList
            }),
          ...mapGetters([
          	'getKeyword'
          ])
        },
        created(){
        	this.changeTitle('搜索');
        	this.changeBackground('#fff');
            let _self=this;
            setTimeout(()=>{
            	_self.pushHistory();
                _self.canPushState=false;
            },0);
        },
        mounted(){
          window.addEventListener('popstate',this.pushHistory,false);
        },
        destroyed(){
          window.removeEventListener('popstate',this.pushHistory,false);
        }
    })
</script>
<style lang="scss" scoped>
    .search-view{
        width:10rem;
        margin:0 auto;
        background-color:#fff;
        font-family: NotoSansHans;
        .top-bar{
            width:100%;
            padding:.54rem .2666rem;
            .bg{
                position:relative;
                width:100%;
                height:.9rem;
                padding:0 .4rem;
                background-color:#e4e4e4;
                border-radius:.4533rem;
                input::-webkit-input-placeholder, textarea::-webkit-input-placeholder {
                    color: #222;
                }
                .search-input{
                    width:100%;
                    height:100%;
                    line-height:.92rem;
                    background-color:transparent;
                    outline: none;
                    font-size: .32rem;
                }
                .clear-btn{
                    position:absolute;
                    right:1rem;
                    top:.06rem;
                    border:none;
                    outline: none;
                    -webkit-appearance: none;
                    background-color:transparent;
                    padding:.2rem;
                }
                .clear{
                    display:inline-block;
                    width:.4rem;
                    height:.4rem;
                    border-radius: 50%;
                    line-height:.4rem;
                    background-color:rgba(80,80,80,.8);
                    font-size: .4rem;
                    color:#fff;

                }
                .icon-wrapper{
                    position:absolute;
                    right:.4rem;
                    top:.26rem;
                }
                .icon-search{
                    width:.4rem;
                    height:.4rem;
                    color:#222;

                }
            }
        }
        .keywords{
            background-color:#fff;
            padding:0 .4rem .8rem .4rem;
            .type{
                text-align: left;
                font-size: .3733rem;
                color:#b0b0b0;
            }
            .list{
                text-align: center;
                padding:.32rem 0;
                &:after{
                    content:'';
                    display:block;
                    clear:both;
                }
                li{
                    height:.5333rem;
                    line-height:.54rem;
                    padding:0 .2rem;
                    border:1px solid #b0b0b0;
                    border-radius:5px;
                    float:left;
                    margin-right:10px;
                }
            }
        }
    }
</style>


