<template>
    <div class="swiper-bar">
        <swiper :options="tabOptions" ref="mySwiper">
            <swiper-slide v-for="(tab,index) in tabList" :key="index" @click.native.stop="changeTab(index)">
                <span :class="{'active-color':index===curTab}">
                    {{tab}}
                </span>
            </swiper-slide>
        </swiper>
    </div>
</template>
<script>
    import {swiper, swiperSlide} from 'vue-awesome-swiper'
    import './../modules/css/swiper-3.4.2.min.css'
    export default {
    	components:{
            swiper,
            swiperSlide
        },
    	data(){
    		return {
    			curTab:0,
                tabList:[
                    '默认',
                    '人气',
                    '销量',
                    '新品',
                    '价格最高',
                    '价格最低'
                ],
                tabOptions:{
                    slidesPerView: 'auto',
                    spaceBetween: 0
                }
            }
        },
        methods:{
            changeTab(index){
            	this.curTab=index;
                this.$emit('listenChangeTab',index);
            },
        },
        created(){
    		this.changeTitle(this.$route.params.keyword);
    		this.changeBackground('#fff');
        }
    }
</script>
<style lang="scss">
    .swiper-bar{
        $active-color:#e53a40;
        background-color:#fff;
        .active-color{
            color:$active-color;
        }
        border-bottom:1px solid #e4e4e4;
        line-height:1.2rem;
        font-size:.4rem;
        .swiper-slide{
            display:inline-block;
            padding:0 .4rem;
            width:auto;
        }
    }
</style>


