<template>
    <div class="points-view">
        <div class="wall">
            <h2 class="total-count">{{totalPoints}}</h2>
            <p class="title">积分总计</p>
        </div>
        <div class="detail">
            <div class="title">
                <h3>使用明细</h3>
                <span class="icon-rectangle"></span>
            </div>
            <ul class="list">
                <li v-for="operate in operateList">
                    <p class="change-count">
                        <span class="count">{{operate.change}}</span>
                        <span class="icon-circle"></span>
                    </p>
                    <div class="change-operate">
                        <p class="operate">{{operate.operate}}</p>
                        <p class="time">{{operate.time}}</p>
                    </div>
                </li>
            </ul>
        </div>
    </div>
</template>
<script>
  import { mapState } from 'vuex'
    export default ({
      data(){
        return {

        }
      },
      methods:{

      },
      created(){
      	this.changeTitle('积分');
      	this.changeBackground('#f7f7f7');
      },
      computed:{
        ...mapState({
          totalPoints: state => state.points.totalPoints,
          operateList: state => state.points.operateList
        })
      }
    })
</script>
<style lang="scss" scoped>
    .points-view{
        width:10rem;
        margin:0 auto;
        background-color:#f7f7f7;
        font-family: NotoSansHans;
        .wall{
            width:100%;
            height:3.4933rem;
            padding:.72rem 0;
            background-repeat: no-repeat;
            background-size:100% 100%;
            background-image:url('./../assets/integral-bg.jpg');
            text-align: center;
            color:#fff;
            .total-count{
                font-weight: bold;
                font-size: 1.066rem;
                line-height: 1.4rem;
            }
            .title{
                font-weight: 300;
                font-size:.3733rem;
                line-height: .6rem;
            }
        }
        .detail{
            text-align: left;
            padding:.2rem .4rem;
            .title{
                h3{
                    font-size: .3733rem;
                }
                color:#222;
                line-height:.8rem;
                padding-left:.4rem;
            }
            .list{
                li{
                    .change-count{
                        position:relative;
                        line-height:.6rem;
                        font-size: .4266rem;
                        font-weight: bold;
                        color:#222;
                        padding-left:.52rem;
                        .icon-circle{
                            position:absolute;
                            left:0;
                            top:50%;
                            -webkit-transform: translate3d(0,-50%,0);
                            -moz-transform: translate3d(0,-50%,0);
                            -ms-transform: translate3d(0,-50%,0);
                            -o-transform: translate3d(0,-50%,0);
                            transform: translate3d(0,-50%,0);
                            display:inline-block;
                            width:10px;
                            height:10px;
                            border-radius:50%;
                            background-color:#e4e4e4;
                        }
                    }
                    .change-operate{
                        margin:8px 0 8px 4px;
                        border-left:2px solid #e4e4e4;
                        padding:.2rem 0 .2rem .4rem;
                        p{
                            line-height:.52rem;
                            font-size: .32rem;
                            font-weight: 500;
                        }
                        .operate{
                            color:#222;
                        }
                        .time{
                            color:#b0b0b0;

                        }
                    }
                }
            }
        }
    }
</style>


