<template>
    <div class="track-view">
        <div class="main">
            <div class="track-wrapper">
                <ul class="track-list">
                    <li v-for="(track,index) in trackList" :key="index">
                        <p class="date">
                            <span class="circle"></span>
                            <span>{{track.date}}</span>
                        </p>
                        <div class="prod-wrapper">
                            <ul class="prod-list">
                                <li v-for="(prod,index2) in track.prodList" :key="index2" @click="toProduct(prod.id)">
                                    <div class="img-wrapper">
                                        <img :src="prod.img" :alt="prod.name">
                                    </div>
                                    <div class="text-wrapper">
                                        <h3 class="name">{{prod.name}}</h3>
                                        <p class="price">&yen; {{prod.price}}</p>
                                    </div>
                                    <div class="btn-wrapper">
                                        <mt-button size="small" type="danger" @click.native="toProduct(prod.id)">立即购买</mt-button>
                                    </div>
                                </li>
                            </ul>
                        </div>
                    </li>
                </ul>
            </div>
        </div>
    </div>
</template>
<script>
    import { mapState } from 'vuex'
    export default {
        data(){
        	return {

            }
        },
        created(){
        	this.changeTitle('足迹');
        	this.changeBackground('#fff');
        },
        computed:{
          ...mapState({
            trackList: state => state.track.trackList
          })
        }
    }
</script>
<style lang="scss" scoped>
    .track-view{
        width:100%;
        background-color:#fff;
        font-family: "PingFang SC";
        text-align: left;
        .track-wrapper{
            padding:.2rem 0 0 .48rem;
        }
        .track-list{
            .date{
                position:relative;
                line-height:1rem;
                padding-left:20px;
                font-family: NotoSansHans;
                font-weight: 500;
                color:#b0b0b0;
            }
            .circle{
                position:absolute;
                left:2px;
                top:50%;
                -webkit-transform: translate3d(0,-50%,0);
                -moz-transform: translate3d(0,-50%,0);
                -ms-transform: translate3d(0,-50%,0);
                -o-transform: translate3d(0,-50%,0);
                transform: translate3d(0,-50%,0);
                width:10px;
                height:10px;
                background-color:#e4e4e4;
                border-radius: 50%;
            }
        }
        .prod-list{
            li{
                position:relative;
                border-bottom:1px solid #e4e4e4;
                padding:.52rem .48rem .52rem 2.2rem;
                &:last-child{
                    border:none;
                }
            }
            .img-wrapper{
                position:absolute;
                left:0;
                top:.52rem;
                width:1.8666rem;
                height:1.8666rem;
                img{
                    width:100%;
                    height:100%;
                }
            }
            .text-wrapper{
                .name{
                    font-size: .3733rem;
                    font-weight: 500;
                    line-height:.56rem;
                    color:#222;
                    width:4rem;
                    height:1rem;
                    display: -webkit-box;
                    -webkit-box-orient: vertical;
                    -webkit-line-clamp: 2;
                    overflow: hidden;
                }
                .price{
                    font-size: .4rem;
                    color:#d43b40;
                    font-weight: bold;
                    margin-top:.4rem;
                }
            }
            .btn-wrapper{
                position:absolute;
                right:.48rem;
                bottom:.52rem;
                .mint-button--small{
                    font-size: .3466rem;
                    padding:0;
                    line-height:.728rem;
                    height:.68rem;
                    width:1.8rem;
                    margin-right:.2rem;
                }
            }
        }
    }
</style>


