// 首页模块
const state = {
   keyword:'',
   placeholder:'推荐搜索关键字',
   historyList:[
     'A2奶粉乐',
     '冠生园',
     '纸尿裤'
   ],
   hotList:[
     'A2奶粉乐',
     '冠生园',
     '纸尿裤'
   ]
}
const mutations={
  clearKeyword(state){
    state.keyword='';
  },
  changeKeyword(state,keyword){
    state.keyword=keyword;
  },
  search(){

  }
}
const actions={
  clearKeyword({commit}){
    commit('clearKeyword');
  }
}
const getters={
  getKeyword(){
    return state.keyword;
  }
}
export default {
    state,
    mutations,
    actions,
    getters
}


