<template>
    <div class="v-prod" @click="toProduct(prod.prodId)">
        <div class="img-wrapper">
            <img :src="prod.img">
        </div>
        <div class="text-wrapper">
            <h3 class="name">{{prod.name}}</h3>
            <p class="price">
                <span class="current">&yen; {{prod.curPrice}}</span>
                <span class="original">&yen; {{prod.originalPrice}}</span>
            </p>
        </div>
    </div>
</template>
<script>
    export default {
    	props:['prod']
    }
</script>
<style lang="scss" scoped>
    .v-prod{
        width:4.2rem;
        text-align: left;
        .img-wrapper{
            width:4.2rem;
            height:4.2rem;
            img{
                width:100%;
                height:100%;
            }
        }
        .text-wrapper{
            margin:.2rem 0;
            .name{
                line-height:.4rem;
                height:.72rem;
                font-size: .32rem;
                color:#222;
                display: -webkit-box;
                -webkit-box-orient: vertical;
                -webkit-line-clamp: 2;
                overflow: hidden;
            }
            .price{
                margin-top:.2rem;
                line-height:.6rem;
                .current{
                    font-size:.4533rem;
                    color:#e53c30;
                }
                .original{
                    padding-left:.2rem;
                    font-size: .3466rem;
                    color:#b0b0b0;
                }
            }
        }
    }
</style>


