<template>
  <div class="home-view">
    <router-view></router-view>
    <mt-tabbar v-model="selected" :fixed="true">
      <mt-tab-item id="/index">
        <router-link to="/home/index">
          <svg class="icon" aria-hidden="true">
            <use xlink:href="#icon-shouye"></use>
          </svg>
          <label class="footer-bar-label">首页</label>
        </router-link>
      </mt-tab-item>
      <mt-tab-item id="/category">
        <router-link to="/home/category">
          <svg class="icon" aria-hidden="true">
            <use xlink:href="#icon-fenlei"></use>
          </svg>
          <label class="footer-bar-label">分类</label>
        </router-link>
      </mt-tab-item>
      <mt-tab-item id="/cart">
        <router-link to="/home/cart">
          <svg class="icon" aria-hidden="true">
            <use xlink:href="#icon-gouwuche"></use>
          </svg>
          <label class="footer-bar-label">购物车</label>
        </router-link>
      </mt-tab-item>
      <mt-tab-item id="/user">
        <router-link to="/home/user">
          <svg class="icon" aria-hidden="true">
            <use xlink:href="#icon-wode"></use>
          </svg>
          <label class="footer-bar-label">我的</label>
        </router-link>
      </mt-tab-item>
    </mt-tabbar>
  </div>
</template>
<script>
  export default ({
      data(){
        return {
          selected:'/index',
        }
      },
      created(){
          let len=this.$route.path.length;
          this.selected=this.$route.path.substring(5,len);
      },
      computed:{
        getPath(){
          return this.$route.path;
        }
      },
      watch:{
        'getPath'(newVal,oldVal){
          let len=newVal.length;
  //        console.log(newVal.substring(5,len));
          this.selected=newVal.substring(5,len);
        }
      }
  })
</script>
<style lang="scss">
    $active-color:#e53a40;
    $dark-color:#b0b0b0;
    $bar-height:1.3333rem;
  .home-view{
      width:100%;
      margin-bottom:$bar-height;
      .mint-tabbar{
          height:1.3333rem;
          overflow: hidden;
          background-image: none;
          border-top:1px solid #e4e4e4;
      }
      .mint-tabber.is-fixed{
          z-index:1000;
      }
      .mint-tab-item{
          padding:0;
      }
      .mint-tab-item .footer-bar-label{
          display:block;
          font-size:.2rem;
          line-height:.4rem;
          font-family: NotoSansHans;
      }
      .mint-tabbar > .mint-tab-item.is-selected .icon{
          color:$active-color;
          fill: currentColor;
      }
      .mint-tab-item-label>a{
          display:block;
          padding-top:.2rem;
          color:$dark-color;
          text-decoration: none;
      }
      .mint-tab-item.is-selected .mint-tab-item-label .footer-bar-label{
          color:$active-color;
      }
      .mint-tabbar > .mint-tab-item.is-selected{
          background: transparent;
      }
  }
</style>



