const mutations={
  checkAllProd(state,event){
      // console.log(event);
      if(event&&event.currentTarget&&event.currentTarget.querySelector('input')&&event.currentTarget.querySelector('input').getAttribute('disabled')){
        return false;
      }
      state.ready.allChecked=!state.ready.allChecked;
      if(state.ready.allChecked){
        for(let [index,store] of state.orderList.entries()){
          store.isChecked=true;
          for(let [index2,prod] of store.list.entries()){
            if(prod.isValid){
              prod.isChecked=true;
            }
          }
        }
      }else{
        for(let [index,store] of state.orderList.entries()){
          store.isChecked=false;
          for(let [index2,prod] of store.list.entries()){
            if(prod.isValid){
              prod.isChecked=false;
            }
          }
        }
      }
  },
  changeEdit(state){
    state.isEdit=!state.isEdit;
    if(state.isEdit){
      state.editText='完成';
    }else{
      state.editText='编辑';
    }
  }
}
const actions={
  checkAllProd({commit},event){
      commit('checkAllProd',event);
  },
  changeEdit({commit}){
    commit('changeEdit')
  }
}
export default {
    state,
    mutations,
    actions
}



